// ─── CALCULATIONS ─────────────────────────────────────────────────────────────
function calcBMR(w, h, age, gender) {
  return gender === "M"
    ? 88.362 + 13.397 * w + 4.799 * h - 5.677 * age
    : 447.593 + 9.247 * w + 3.098 * h - 4.33 * age;
}
const ACT = { Sedentary: 1.2, Light: 1.375, Moderate: 1.55, Active: 1.725, "Very Active": 1.9 };
const GOAL_CFG = {
  "Weight Loss": { pct: [0.40, 0.30, 0.30], adj: -500, icon: "⚖️", color: "#E53935", pricing: { week4: 50, week8: 100, week12: 200 } },
  "Fat Loss + Tone": { pct: [0.42, 0.28, 0.30], adj: -400, icon: "🎽", color: "#e91e63", pricing: { week4: 60, week8: 120, week12: 240 } },
  "Lean Muscle": { pct: [0.35, 0.40, 0.25], adj: +200, icon: "✨", color: "#00897b", pricing: { week4: 70, week8: 140, week12: 280 } },
  "Body Building": { pct: [0.35, 0.45, 0.20], adj: +400, icon: "💪", color: "#5e35b1", pricing: { week4: 80, week8: 160, week12: 320 } },
  "CrossFit": { pct: [0.30, 0.45, 0.25], adj: +100, icon: "🔥", color: "#f57c00", pricing: { week4: 75, week8: 150, week12: 300 } },
  "Sports Performance": { pct: [0.28, 0.50, 0.22], adj: +150, icon: "⚡", color: "#0288d1", pricing: { week4: 70, week8: 140, week12: 280 } },
  "Maintenance": { pct: [0.30, 0.45, 0.25], adj: 0, icon: "⚙️", color: "#546e7a", pricing: { week4: 50, week8: 100, week12: 200 } },
};

function calcMetrics(c) {
  const bmr = calcBMR(c.weight, c.height, c.age, c.gender);
  const tdee = bmr * (ACT[c.activity] || 1.55);
  const { pct, adj } = GOAL_CFG[c.goal] || GOAL_CFG.Maintenance;
  const targetCal = Math.round(tdee + adj);
  const bmi = +(c.weight / ((c.height / 100) ** 2)).toFixed(1);
  const bmiLabel = bmi < 18.5 ? "Underweight" : bmi < 25 ? "Normal" : bmi < 30 ? "Overweight" : "Obese";
  const bmiColor = bmi < 18.5 ? "#0288d1" : bmi < 25 ? "#2e7d32" : bmi < 30 ? "#f57c00" : "#c62828";
  return {
    bmr: Math.round(bmr), tdee: Math.round(tdee), targetCal,
    bmi, bmiLabel, bmiColor,
    protein: Math.round((targetCal * pct[0]) / 4),
    carbs: Math.round((targetCal * pct[1]) / 4),
    fat: Math.round((targetCal * pct[2]) / 9),
    water: +(c.weight * 35 / 1000).toFixed(1),
  };
}

// ─── DYNAMIC PRICING CALCULATION ───────────────────────────────────────────────
function getPricing(goal, medical = "None") {
  const basePricing = (GOAL_CFG[goal] || GOAL_CFG.Maintenance).pricing;
  let medicalSurcharge = 0;
  
  // Add surcharge for medical conditions
  if (medical && medical !== "None") {
    const complexConditions = ["Diabetes", "Hypertension", "Heart Disease", "Thyroid"];
    medicalSurcharge = complexConditions.includes(medical) ? 20 : 10;
  }
  
  return {
    week4: basePricing.week4 + medicalSurcharge,
    week8: basePricing.week8 + medicalSurcharge,
    week12: basePricing.week12 + medicalSurcharge,
  };
}

